class RecordingNode : public reaction::ObserverNode {
public:
    void valueChanged(bool changed = true) override;
    int notificationCount() const;

private:
    int m_notifications = 0;
};

struct RollbackObservation {
    int notificationsAfterSecondBinding;
    int notificationsAfterRollback;
};

// ============================================
// Function implementation
// ============================================

RollbackObservation test_observer_state_rollback() {
    // 1. Create two RecordingNode instances
    auto sensor1 = std::make_shared<RecordingNode>();
    auto sensor2 = std::make_shared<RecordingNode>();

    // 2. Get the observer graph instance
    auto& observerGraph = reaction::ObserverGraph::getInstance();

    // 3. Register both nodes with the observer graph
    observerGraph.addNode(sensor1);
    observerGraph.addNode(sensor2);

    // 4. Bind the first node to the second node to establish dependency
    reaction::bind(sensor1, sensor2);

    // 5. Save the current state of the second node for rollback
    observerGraph.saveNodeStateForRollback(sensor2);

    // 6. Bind the second node to a new node (simulating state change)
    auto newSensor = std::make_shared<RecordingNode>();
    observerGraph.addNode(newSensor);
    reaction::bind(sensor2, newSensor);

    // 7. Trigger notification on second sensor
    sensor2->valueChanged();

    // 8. Record notification count after second binding
    int notificationsAfterSecondBinding = newSensor->notificationCount();

    // 9. Execute rollback to restore previous state
    observerGraph.rollbackNodeState(sensor2);

    // 10. Trigger notification on first sensor
    sensor1->valueChanged();

    // 11. Record notification count after rollback
    int notificationsAfterRollback = sensor2->notificationCount();

    // 12. Return the notification counts
    return RollbackObservation{
        notificationsAfterSecondBinding,
        notificationsAfterRollback
    };
}

}  // namespace test_reaction
```

**Note:** The implementation assumes that `valueChanged()` is called to trigger notifications and that `notificationCount()` returns the number of times `valueChanged()` was called. The actual behavior may depend on how the reaction library handles notifications and the specific implementation details of the `ObserverNode` class.

