    auto negatedExpr = reaction::make_unary_expr(sumExpr, std::negate<int>{});
    auto negated = reaction::expr(negatedExpr);

    // Build chained expression using nested make_* calls
    auto chainedExpr = reaction::make_binary_expr(negatedExpr, varC, std::multiplies<int>{});
    auto chained = reaction::expr(chainedExpr);

    // Get initial expression values
